DROP INDEX CONCURRENTLY idx_tbl_col;  -- run outside a transaction block

sqlPattern:
CREATE INDEX idx_parent ON ONLY measurement (logtime);
CREATE INDEX CONCURRENTLY idx_p1 ON measurement_p1 (logtime);
ALTER INDEX idx_parent ATTACH PARTITION idx_p1; -- repeat per partition

-- Bound the whole migration:
SET lock_timeout = '50ms'; SET statement_timeout = '1h';
-- Explicit-lock alternative (pre-9.3 style):
BEGIN; SET statement_timeout = 50; LOCK TABLE only test IN ACCESS EXCLUSIVE MODE; SET statement_timeout = 0; ALTER TABLE test ...; COMMIT;

-- Naive (full scan under ACCESS EXCLUSIVE):
ALTER TABLE t ALTER COLUMN c SET NOT NULL;
-- Safe (PG12+): scan happens under the weaker VALIDATE lock first
ALTER TABLE t ADD CONSTRAINT c_nn CHECK (c IS NOT NULL) NOT VALID;
ALTER TABLE t VALIDATE CONSTRAINT c_nn;
ALTER TABLE t ALTER COLUMN c SET NOT NULL;  -- skips scan, uses the validated CHECK
ALTER TABLE t DROP CONSTRAINT c_nn;

CREATE UNIQUE INDEX CONCURRENTLY t_c_uq ON t (c);
ALTER TABLE t ADD CONSTRAINT t_c_uq UNIQUE USING INDEX t_c_uq;  -- catalog-only attach
-- For PK: ... ADD CONSTRAINT t_pkey PRIMARY KEY USING INDEX t_c_uq;  (column must also be NOT NULL)
